import { setup, assign, fromPromise } from 'xstate';

type User = { id: string; name: string };

const fetchUser = fromPromise(async ({ input }: { input: { id: string } }): Promise<User> => {
  const res = await fetch(`/api/users/${input.id}`);
  if (!res.ok) throw new Error('Failed to fetch user');
  return res.json();
});

export const userMachine = setup({
  types: {
    context: {} as { id: string; user: User | null; error: string | null },
    events: {} as { type: 'FETCH'; id: string },
  },
  actors: { fetchUser },
}).createMachine({
  id: 'user',
  initial: 'idle',
  context: { id: '', user: null, error: null },
  states: {
    idle: {
      on: {
        FETCH: {
          target: 'loading',
          actions: assign({ id: ({ event }) => event.id }),
        },
      },
    },
    loading: {
      invoke: {
        src: 'fetchUser',
        input: ({ context }) => ({ id: context.id }),
        onDone: {
          target: 'success',
          actions: assign({ user: ({ event }) => event.output }),
        },
        onError: {
          target: 'failed',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    success: { type: 'final' },
    failed: { on: { FETCH: 'loading' } },
  },
});
