export const downloadMachine = setup({
  types: {
    context: {} as { progress: number; error: string | null },
    events: {} as
      | { type: 'START' }
      | { type: 'PAUSE' }
      | { type: 'RESUME' }
      | { type: 'PROGRESS'; amount: number }
      | { type: 'COMPLETE' }
      | { type: 'FAIL'; reason: string },
  },
  guards: {
    isDownloading: ({ context }) => context.progress < 100,
  },
}).createMachine({
  id: 'download',
  initial: 'idle',
  context: { progress: 0, error: null },
  states: {
    idle: { on: { START: 'downloading' } },
    downloading: {
      on: {
        PROGRESS: {
          actions: assign({
            progress: ({ context, event }) => Math.min(100, context.progress + event.amount),
          }),
        },
        PAUSE: { target: 'paused', guard: 'isDownloading' },
        COMPLETE: 'done',
        FAIL: {
          target: 'error',
          actions: assign({ error: ({ event }) => event.reason }),
        },
      },
    },
    paused: { on: { RESUME: 'downloading' } },
    done: { type: 'final' },
    error: { on: { START: 'downloading' } },
  },
});
