import { setup, assign, fromCallback } from 'xstate';

const wsListener = fromCallback<{ type: string }, { url: string }>(({ sendBack, input }) => {
  const socket = new WebSocket(input.url);
  socket.addEventListener('message', (e) => {
    sendBack({ type: 'MESSAGE', data: e.data });
  });
  return () => socket.close();
});

export const wsMachine = setup({
  types: {
    context: {} as { url: string; messages: string[] },
    events: {} as { type: 'CONNECT'; url: string } | { type: 'MESSAGE'; data: string },
  },
  actors: { wsListener },
}).createMachine({
  id: 'ws',
  initial: 'idle',
  context: { url: '', messages: [] },
  states: {
    idle: {
      on: {
        CONNECT: {
          target: 'connected',
          actions: assign({ url: ({ event }) => event.url }),
        },
      },
    },
    connected: {
      invoke: { src: 'wsListener', input: ({ context }) => ({ url: context.url }) },
      on: {
        MESSAGE: {
          actions: assign({
            messages: ({ context, event }) => [...context.messages, event.data],
          }),
        },
      },
    },
  },
});
