export const signupMachine = setup({
  types: {
    context: {} as {
      email: string;
      password: string;
      confirm: string;
      error: string | null;
    },
    events: {} as
      | { type: 'SET_EMAIL'; value: string }
      | { type: 'SET_PASSWORD'; value: string }
      | { type: 'SET_CONFIRM'; value: string }
      | { type: 'NEXT' }
      | { type: 'BACK' }
      | { type: 'SUBMIT' },
  },
  actors: { checkEmail },
  guards: {
    passwordsMatch: ({ context }) => context.password === context.confirm && context.password.length >= 8,
  },
}).createMachine({
  id: 'signup',
  initial: 'email',
  context: { email: '', password: '', confirm: '', error: null },
  states: {
    email: {
      on: {
        SET_EMAIL: { actions: assign({ email: ({ event }) => event.value }) },
        NEXT: 'validatingEmail',
      },
    },
    validatingEmail: {
      invoke: {
        src: 'checkEmail',
        input: ({ context }) => ({ email: context.email }),
        onDone: [
          { target: 'password', guard: ({ event }) => event.output },
          { target: 'email', actions: assign({ error: 'Email already in use' }) },
        ],
        onError: { target: 'email', actions: assign({ error: 'Validation failed' }) },
      },
    },
    password: {
      on: {
        SET_PASSWORD: { actions: assign({ password: ({ event }) => event.value }) },
        NEXT: 'confirm',
        BACK: 'email',
      },
    },
    confirm: {
      on: {
        SET_CONFIRM: { actions: assign({ confirm: ({ event }) => event.value }) },
        SUBMIT: { target: 'done', guard: 'passwordsMatch' },
        BACK: 'password',
      },
    },
    done: { type: 'final' },
  },
});
