                guard: ({ context }) => context.items.length === 1,
                actions: assign({ items: [] }),
              },
              {
                actions: assign({
                  items: ({ context, event }) => context.items.filter((i) => i !== event.item),
                }),
              },
            ],
          },
        },
      },
      on: { CHECKOUT: 'checkingOut' },
    },
    checkingOut: { type: 'final' },
  },
