export const authMachine = setup({
  types: {
    context: {} as { session: Session | null; error: string | null },
    events: {} as { type: 'LOGIN'; credentials: Credentials } | { type: 'LOGOUT' },
  },
  actors: { login },
}).createMachine({
  id: 'auth',
  initial: 'loggedOut',
  context: { session: null, error: null },
  states: {
    loggedOut: {
      on: { LOGIN: 'loggingIn' },
    },
    loggingIn: {
      invoke: {
        src: 'login',
        input: ({ event }) => {
          if (event.type !== 'LOGIN') throw new Error('unreachable');
          return event.credentials;
        },
        onDone: {
          target: 'loggedIn',
          actions: assign({ session: ({ event }) => event.output, error: null }),
        },
        onError: {
          target: 'loggedOut',
          actions: assign({ error: ({ event }) => String(event.error) }),
        },
      },
    },
    loggedIn: {
      on: {
        LOGOUT: {
          target: 'loggedOut',
          actions: assign({ session: null }),
        },
      },
    },
  },
