import { setup, assign, fromPromise } from 'xstate';

const fetcher = fromPromise(async ({ input }: { input: { url: string } }): Promise<string> => {
  const res = await fetch(input.url);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.text();
});

export const fetchMachine = setup({
  types: {
    context: {} as { url: string; data: string | null; attempts: number; maxAttempts: number },
    events: {} as { type: 'FETCH'; url: string },
  },
  actors: { fetcher },
  guards: {
    canRetry: ({ context }) => context.attempts < context.maxAttempts,
  },
}).createMachine({
  id: 'fetch',
  initial: 'idle',
  context: { url: '', data: null, attempts: 0, maxAttempts: 3 },
  states: {
    idle: {
      on: {
        FETCH: {
          target: 'fetching',
          actions: assign({ url: ({ event }) => event.url, attempts: 0 }),
        },
      },
    },
    fetching: {
      invoke: {
        src: 'fetcher',
        input: ({ context }) => ({ url: context.url }),
        onDone: { target: 'success', actions: assign({ data: ({ event }) => event.output }) },
        onError: [
          { target: 'retrying', guard: 'canRetry' },
          { target: 'failed' },
        ],
      },
    },
    retrying: {
      entry: assign({ attempts: ({ context }) => context.attempts + 1 }),
      after: { 1000: 'fetching' },
    },
    success: { type: 'final' },
    failed: { on: { FETCH: { target: 'fetching', actions: assign({ attempts: 0 }) } } },
  },
});
