      invoke: {
        src: 'connect',
        input: ({ context }) => ({ url: context.url }),
        onDone: {
          target: 'connected',
          actions: assign({ socket: ({ event }) => event.output }),
        },
        onError: 'reconnecting',
      },
    },
    connected: {
      on: { DISCONNECT: 'disconnected' },
    },
